from google.adk import Session

def audit_session_pii(session: Session) -> dict:
    state_text = str(session.state)
    pii_patterns = {
        'emails': len(re.findall(r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b', state_text)),
        'phones': len(re.findall(r'\b\d{3}-?\d{2}-?\d{4}\b', state_text)),
        'ssn': len(re.findall(r'\b\d{3}-?\d{2}-?\d{4}\b', state_text))
    }
    return {'pii_detected': sum(pii_patterns.values()), 'details': pii_patterns}

