from google.adk.tools import ToolResponse

def detect_tool_pii(response: ToolResponse) -> bool:
    content = response.content
    pii_indicators = [
        'email' in content.lower(),
        any(d in content for d in ['@gmail', '@yahoo', '@outlook']),
        re.search(r'\d{3}-\d{2}-\d{4}', content),
        len(re.findall(r'\d{4}-\d{4}-\d{4}-\d{4}', content)) > 0
    ]
    return any(pii_indicators)

# Integrate in tool callback
if detect_tool_pii(tool_response):
    print('PII detected in tool response - blocking')

