from google.adk.tools import ToolResponse

def safe_tool_response(tool_resp: ToolResponse) -> ToolResponse:
    if has_pii(tool_resp.content):
        return ToolResponse(
            content='[PII DETECTED - RESPONSE BLOCKED]',
            status='blocked'
        )
    return tool_resp

def has_pii(text: str) -> bool:
    return bool(re.search(r'(@[a-z]+\.[a-z]{2,}|\d{3}-\d{2}-\d{4})', text))

